const items = $input.all();

let emails = [];

items.forEach(item => {
  const json = item.json;

  // Use a Map to deduplicate recipients per comment
  const recipientsMap = new Map();

  // 1️⃣ Issue owner
  if (json.issue_owner_email) {
    recipientsMap.set(json.issue_owner_email, {
      email: json.issue_owner_email,
      firstname: json.issue_owner_firstname,
      lastname: json.issue_owner_lastname,
    });
  }

  // 2️⃣ Mentioned users
  if (json.mentioned_user_email) {
    recipientsMap.set(json.mentioned_user_email, {
      email: json.mentioned_user_email,
      firstname: json.mentioned_user_firstname || '',
      lastname: json.mentioned_user_lastname || '',
    });
  }

  // 3️⃣ Build email objects per recipient
  recipientsMap.forEach(recipient => {
    emails.push({
      json: {
        comment_id: json.comment_id,
        comment_body: json.comment_body,
        comment_created_at: json.comment_created_at,
        commented_by_firstname: json.commented_by_firstname,
        commented_by_lastname: json.commented_by_lastname,

        issue_id: json.issue_id,
        issue_title: json.issue_title,
        issue_created_at: json.issue_created_at,
        issue_end_date: json.issue_end_date,
        issue_status: json.issue_status,
        issue_priority: json.issue_priority,

        project_id: json.project_id,
        project_title: json.project_title,

        milestone_id: json.milestone_id,
        milestone_title: json.milestone_title,

        task_id: json.task_id,
        task_title: json.task_title,

        recipient_email: recipient.email,
        recipient_firstname: recipient.firstname,
        recipient_lastname: recipient.lastname
      }
    });
  });
});

return emails;

return emails;

